public void testInlineFunctions31_nested() {
  // Test nested labels with same name in function and outer scope
  test("function foo(){ outer:{inner:{5;}} }" +
      "outer:{foo();}",
      "outer:{{JSCompiler_inline_label_outer_0:{JSCompiler_inline_label_inner_1:{5}}}}");
}

public void testInlineFunctions31_unreferenced() {
  // Test unreferenced label in function doesn't conflict with outer label
  test("function foo(){ lab:{break lab;} }" +
      "lab:{foo();}",
      "lab:{{JSCompiler_inline_label_0:{break JSCompiler_inline_label_0}}}");
}

public void testInlineFunctions31_multiple() {
  // Test multiple labels in function with outer scope conflicts
  test("function foo(){ a:{1;} b:{2;} }" +
      "a:{b:{foo();}}",
      "a:{b:{{JSCompiler_inline_label_a_0:{1} JSCompiler_inline_label_b_1:{2}}}}");
}
